"""
OpenAI Speech-to-Text provider module for Spikee.

Additional Args:

"""
import base64
from io import BytesIO
import os

from spikee.templates.provider import Provider
from spikee.utilities.enums import ModuleTag
from spikee.utilities.llm_message import Message, upgrade_messages, AIMessage, HumanMessage, SystemMessage, format_messages
from typing import List, Tuple, Dict, Union




class OpenAISTTProvider(Provider):
    """OpenAI Speech-to-Text provider"""

    @property
    def default_model(self) -> str:
        return "gpt-4o-mini-transcribe"

    @property
    def models(self) -> Dict[str, str]:
        return {
            "gpt-4o-mini-transcribe": "gpt-4o-mini-transcribe",
            "gpt-4o-transcribe": "gpt-4o-transcribe", 
            "gpt-4o-transcribe-diarize": "gpt-4o-transcribe-diarize",
            "whisper-1": "whisper-1",
        }

    def setup(
        self,
        model: str,
        max_tokens: Union[int, None] = None,
        temperature: Union[float, None] = None,
        **additional_kwargs,
    ) -> None:
        self.model = model

        try:
            from openai import OpenAI
            self.client = OpenAI(api_key=os.getenv("OPENAI_API_KEY"))
        except ImportError:
            raise ImportError(
                "[Import Error] Provider Module 'openai_stt' is missing required packages. "
                "Please run `pip install spikee[openai]` to install them."
            )

    def get_description(self) -> Tuple[List[ModuleTag], str]:
        return [ModuleTag.AUDIO, ModuleTag.LLM], "STT Provider for OpenAI speech-to-text models."

    def _detect_audio_format(self, audio_bytes: bytes) -> str:
        if audio_bytes[:3] == b'ID3' or audio_bytes[:2] in (b'\xff\xfb', b'\xff\xf3', b'\xff\xf2'):
            return 'mp3'
        elif audio_bytes[:4] == b'RIFF':
            return 'wav'
        elif audio_bytes[:4] == b'OggS':
            return 'ogg'
        elif audio_bytes[:4] == b'fLaC':
            return 'flac'
        else:
            return 'mp3'


    def invoke(
        self, messages: Union[str, List[Union[Message, dict, tuple, str]]]
    ) -> AIMessage:
        """Invoke OpenAI STT with the provided audio. Returns transcribed text in metadata."""
        
        messages = upgrade_messages(messages)
        
        if len(messages) > 1 and not isinstance(messages[0], HumanMessage):
            raise ValueError("OpenAI TTS Provider only supports an instruction an user prompt input.")
    
        else:
            try:
                audio_bytes = base64.b64decode(messages[0].content)
                ext = self._detect_audio_format(audio_bytes)
                audio_buffer = BytesIO(audio_bytes)
                audio_buffer.name = f"input_audio.{ext}"
            except Exception as e:
                raise ValueError("Failed to decode base64 audio content.") from e

        
        response = self.client.audio.transcriptions.create(
            model=self.model,
            file=audio_buffer,
            response_format="text",
        )

        transcribed_text = response.rstrip()

        return AIMessage(
            content=transcribed_text
        )

if __name__ == "__main__":
    from dotenv import load_dotenv
    load_dotenv()
    
    provider = OpenAISTTProvider()
    provider.setup(model="gpt-4o-mini-transcribe")
    messages = [
        HumanMessage(content=""),
    ] # Hello how are you today?
    
    response = provider.invoke(messages)
    print(response.content)